describe('services/recommendations.ts â€” computeTargets()', () => {

  test('returns DEFAULTS when profile is null', () => {
    try {
      const t = computeTargets(null);
      expect(t.calories).toBe(2000);
      expect(t.protein).toBe(160);
      expect(t.sleepHours).toBe(8);
      logResult('computeTargets: null profile â†’ defaults', true);
    } catch (e) { logResult('computeTargets: null profile â†’ defaults', false, e); throw e; }
  });

  test('returns DEFAULTS when weight/height missing', () => {
    try {
      const t = computeTargets({ id: '1', email: 'a@b.com' } as any);
      expect(t.calories).toBe(2000);
      logResult('computeTargets: missing weight/height â†’ defaults', true);
    } catch (e) { logResult('computeTargets: missing weight/height â†’ defaults', false, e); throw e; }
  });

  test('male 80kg 180cm lose_weight â†’ calorie deficit', () => {
    try {
      const t = computeTargets({ id: '1', email: 'x', weight_kg: 80, height_cm: 180, gender: 'male', primary_goal: 'lose_weight', workout_frequency: '3' } as any);
      // BMR = 10*80 + 6.25*180 - 5*30 + 5 = 800 + 1125 - 150 + 5 = 1780
      // TDEE = 1780 * 1.55 = ~2759 â†’ rounded = 2750
      // Target = 2750 - 400 = 2350
      expect(t.calories).toBeGreaterThan(1200);
      expect(t.calories).toBeLessThan(3500);
      expect(t.protein).toBe(Math.round(80 * 2.0)); // 160g
      expect(t.sleepHours).toBe(8);
      expect(t.workoutDaysPerWeek).toBe(4);
      logResult('computeTargets: lose_weight male calorie deficit', true);
    } catch (e) { logResult('computeTargets: lose_weight male calorie deficit', false, e); throw e; }
  });

  test('female 60kg 165cm gain_muscle â†’ calorie surplus', () => {
    try {
      const tMale   = computeTargets({ id: '1', email: 'x', weight_kg: 60, height_cm: 165, gender: 'male',   primary_goal: 'gain_muscle', workout_frequency: '5' } as any);
      const tFemale = computeTargets({ id: '1', email: 'x', weight_kg: 60, height_cm: 165, gender: 'female', primary_goal: 'gain_muscle', workout_frequency: '5' } as any);
      expect(tFemale.calories).toBeLessThan(tMale.calories); // female TDEE lower
      expect(tFemale.protein).toBe(Math.round(60 * 2.2)); // 2.2 g/kg
      logResult('computeTargets: gender-aware TDEE (female < male)', true);
    } catch (e) { logResult('computeTargets: gender-aware TDEE (female < male)', false, e); throw e; }
  });

  test('extreme low calorie floor at 1200 kcal', () => {
    try {
      // Very small person, sedentary, lose weight
      const t = computeTargets({ id: '1', email: 'x', weight_kg: 40, height_cm: 145, gender: 'female', primary_goal: 'lose_weight', workout_frequency: '0' } as any);
      expect(t.calories).toBeGreaterThanOrEqual(1200);
      logResult('computeTargets: calorie floor â‰¥ 1200 kcal', true);
    } catch (e) { logResult('computeTargets: calorie floor â‰¥ 1200 kcal', false, e); throw e; }
  });

  test('GOAL_LABELS covers all onboarding goal keys', () => {
    try {
      const onboardingGoals = ['lose_weight', 'gain_muscle', 'improve_energy', 'better_sleep', 'reduce_stress', 'general_health'];
      onboardingGoals.forEach((g) => expect(GOAL_LABELS[g]).toBeDefined());
      logResult('GOAL_LABELS: all onboarding goals have labels', true);
    } catch (e) { logResult('GOAL_LABELS: all onboarding goals have labels', false, e); throw e; }
  });

  test('macros sum to â‰ˆ calories (within 10%)', () => {
    try {
      const t = computeTargets({ id: '1', email: 'x', weight_kg: 75, height_cm: 175, gender: 'male', primary_goal: 'general_health', workout_frequency: '3' } as any);
      const calsFromMacros = t.protein * 4 + t.carbs * 4 + t.fat * 9;
      const diff = Math.abs(calsFromMacros - t.calories) / t.calories;
      expect(diff).toBeLessThan(0.15); // within 15% (rounding is expected)
      logResult('computeTargets: macros sum â‰ˆ total calories', true);
    } catch (e) { logResult('computeTargets: macros sum â‰ˆ total calories', false, e); throw e; }
  });

  test('waterGlasses is always 8 regardless of goal', () => {
    try {
      const goals = ['lose_weight', 'gain_muscle', 'better_sleep', 'general_health'];
      goals.forEach((g) => {
        const t = computeTargets({ id: '1', email: 'x', weight_kg: 70, height_cm: 175, gender: 'male', primary_goal: g, workout_frequency: '3' } as any);
        expect(t.waterGlasses).toBe(8);
      });
      logResult('computeTargets: waterGlasses always 8', true);
    } catch (e) { logResult('computeTargets: waterGlasses always 8', false, e); throw e; }
  });
});

