describe('services/progressUtils.ts', () => {

  const makeEntries = (weightKg: number, daysAgo: number[]) =>
    daysAgo.map((d) => ({
      date: daysAgoStr(d),
      weight_kg: weightKg,
    }));

  test('detectPlateau: returns false with < 2 entries', () => {
    try {
      expect(detectPlateau([])).toBe(false);
      expect(detectPlateau([{ date: '2025-01-01', weight_kg: 70 }])).toBe(false);
      logResult('detectPlateau: false with < 2 entries', true);
    } catch (e) { logResult('detectPlateau: false with < 2 entries', false, e); throw e; }
  });

  test('detectPlateau: detects stall (< 0.5 kg change over 3 weeks)', () => {
    try {
      const entries = [
        { date: '2025-01-01', weight_kg: 70.1 },
        { date: '2025-01-08', weight_kg: 70.2 },
        { date: '2025-01-15', weight_kg: 70.0 },
        { date: '2025-01-22', weight_kg: 70.3 },
      ];
      expect(detectPlateau(entries, 3)).toBe(true);
      logResult('detectPlateau: detects stall < 0.5 kg', true);
    } catch (e) { logResult('detectPlateau: detects stall < 0.5 kg', false, e); throw e; }
  });

  test('detectPlateau: returns false when weight changed significantly', () => {
    try {
      const entries = [
        { date: '2025-01-01', weight_kg: 72.0 },
        { date: '2025-01-22', weight_kg: 70.0 },
      ];
      expect(detectPlateau(entries, 3)).toBe(false);
      logResult('detectPlateau: false when weight changed > 0.5 kg', true);
    } catch (e) { logResult('detectPlateau: false when weight changed > 0.5 kg', false, e); throw e; }
  });

  test('computeFatigueScore: returns 1 for empty entries', () => {
    try {
      expect(computeFatigueScore([])).toBe(1);
      logResult('computeFatigueScore: returns 1 for empty entries', true);
    } catch (e) { logResult('computeFatigueScore: returns 1 for empty entries', false, e); throw e; }
  });

  test('computeFatigueScore: high energy â†’ low fatigue', () => {
    try {
      const highEnergy = [
        { mood: 5, energy: 5, stress: 1, date: '2025-01-01' },
        { mood: 5, energy: 5, stress: 1, date: '2025-01-02' },
      ];
      const score = computeFatigueScore(highEnergy);
      expect(score).toBe(1); // 6 - 5 = 1
      logResult('computeFatigueScore: energy=5 â†’ fatigue=1', true);
    } catch (e) { logResult('computeFatigueScore: energy=5 â†’ fatigue=1', false, e); throw e; }
  });

  test('computeFatigueScore: low energy â†’ high fatigue', () => {
    try {
      const lowEnergy = [
        { mood: 1, energy: 1, stress: 5, date: '2025-01-01' },
        { mood: 1, energy: 1, stress: 5, date: '2025-01-02' },
      ];
      const score = computeFatigueScore(lowEnergy);
      expect(score).toBe(5); // 6 - 1 = 5
      logResult('computeFatigueScore: energy=1 â†’ fatigue=5', true);
    } catch (e) { logResult('computeFatigueScore: energy=1 â†’ fatigue=5', false, e); throw e; }
  });

  test('suggestAdjustment: fatigue overrides plateau â†’ deload', () => {
    try {
      const result = suggestAdjustment('lose_weight', true, 2000, 4.0);
      expect(result.action).toBe('deload');
      expect(result.calorieAdj).toBe(0);
      logResult('suggestAdjustment: high fatigue â†’ deload action', true);
    } catch (e) { logResult('suggestAdjustment: high fatigue â†’ deload action', false, e); throw e; }
  });

  test('suggestAdjustment: plateau + lose_weight â†’ calorie cut', () => {
    try {
      const result = suggestAdjustment('lose_weight', true, 2000, 1.0);
      expect(result.action).toBe('cut');
      expect(result.calorieAdj).toBeLessThan(0);
      logResult('suggestAdjustment: plateau + lose_weight â†’ calorie cut', true);
    } catch (e) { logResult('suggestAdjustment: plateau + lose_weight â†’ calorie cut', false, e); throw e; }
  });

  test('suggestAdjustment: no plateau â†’ no change', () => {
    try {
      const result = suggestAdjustment('lose_weight', false, 2000, 1.0);
      expect(result.action).toBe('none');
      expect(result.calorieAdj).toBe(0);
      logResult('suggestAdjustment: no plateau â†’ none action', true);
    } catch (e) { logResult('suggestAdjustment: no plateau â†’ none action', false, e); throw e; }
  });

  test('suggestAdjustment: 7.5% calorie cut precision', () => {
    try {
      const result = suggestAdjustment('lose_weight', true, 2000, 1.0);
      expect(result.calorieAdj).toBe(-150); // Math.round(2000 * 0.075) = 150
      logResult('suggestAdjustment: 7.5% cut = 150 kcal on 2000 kcal', true);
    } catch (e) { logResult('suggestAdjustment: 7.5% cut = 150 kcal on 2000 kcal', false, e); throw e; }
  });

  test('suggestAdjustment: every messageKey exists in the dictionary (i18n)', () => {
    try {
      const { en } = require('../constants/i18n/en');
      const cases = [
        suggestAdjustment('lose_weight', true, 2000, 4.0),  // deload
        suggestAdjustment('lose_weight', false, 2000, 1.0), // onTrack
        suggestAdjustment('lose_weight', true, 2000, 1.0),  // cut
        suggestAdjustment('gain_muscle', true, 2000, 1.0),  // overload
        suggestAdjustment('general_health', true, 2000, 1.0), // hiit
      ];
      for (const c of cases) {
        const [section, key] = c.messageKey.split('.');
        expect(typeof (en as any)[section]?.[key]).toBe('string');
      }
      // The cut message interpolates {cut} and {target}
      const cut = cases[2];
      expect(cut.params).toEqual({ cut: 150, target: 1850 });
      logResult('suggestAdjustment: messageKeys exist in en', true);
    } catch (e) { logResult('suggestAdjustment: messageKeys exist in en', false, e); throw e; }
  });

  test('free snap taste: 1/day then paywall (F-pro tiering)', () => {
    try {
      const FREE_SNAP_LIMIT = 1;
      // Simulate the add-food gate: free user with N snaps used TODAY
      const canSnap = (isPro: boolean, usedToday: number) =>
        isPro || Math.max(0, FREE_SNAP_LIMIT - usedToday) > 0;

      expect(canSnap(false, 0)).toBe(true);   // fresh day → one free snap
      expect(canSnap(false, 1)).toBe(false);  // daily quota exhausted → paywall
      expect(canSnap(false, 99)).toBe(false);
      expect(canSnap(true, 99)).toBe(true);   // pro never gated

      // Daily counter, like incrementFreeSnaps + snapsUsedToday: resets when
      // the stored date is not today, increments only on successful analyses.
      const today = '2026-07-19';
      let state = { freeSnapsUsed: 3, freeSnapsDate: '2026-07-18' };
      const usedToday = (s: typeof state) => (s.freeSnapsDate === today ? s.freeSnapsUsed : 0);
      expect(usedToday(state)).toBe(0);       // yesterday's usage doesn't count
      expect(canSnap(false, usedToday(state))).toBe(true);

      state = state.freeSnapsDate === today
        ? { freeSnapsUsed: state.freeSnapsUsed + 1, freeSnapsDate: today }
        : { freeSnapsUsed: 1, freeSnapsDate: today };
      expect(usedToday(state)).toBe(1);       // consumed today's snap
      expect(canSnap(false, usedToday(state))).toBe(false);
      logResult('free snap taste: 1/day then paywall', true);
    } catch (e) { logResult('free snap taste: 1/day then paywall', false, e); throw e; }
  });
});

