// 5. BUSINESS LOGIC â€” onboarding BMI calculation
// â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•

describe('onboarding â€” BMI calculation logic', () => {

  function calcBMI(weightKg: number, heightCm: number): number | null {
    if (!weightKg || !heightCm || weightKg <= 0 || heightCm <= 0) return null;
    const h = heightCm / 100;
    return Math.round((weightKg / (h * h)) * 100) / 100;
  }

  test('calcBMI: known value 70kg / 175cm = 22.86', () => {
    try {
      const bmi = calcBMI(70, 175);
      expect(bmi).toBeCloseTo(22.86, 1);
      logResult('calcBMI: 70kg/175cm â‰ˆ 22.86', true);
    } catch (e) { logResult('calcBMI: 70kg/175cm â‰ˆ 22.86', false, e); throw e; }
  });

  test('calcBMI: returns null for zero/negative inputs', () => {
    try {
      expect(calcBMI(0, 175)).toBeNull();
      expect(calcBMI(70, 0)).toBeNull();
      expect(calcBMI(-5, 175)).toBeNull();
      logResult('calcBMI: null for invalid inputs', true);
    } catch (e) { logResult('calcBMI: null for invalid inputs', false, e); throw e; }
  });

  test('BMI categories cover full range', () => {
    try {
      type BmiCat = { label: string; color: string; comment: string };
      function bmiCategory(bmi: number | null): BmiCat | null {
        if (bmi === null) return null;
        if (bmi < 18.5) return { label: 'Underweight', color: '#3B82F6', comment: '...' };
        if (bmi < 25)   return { label: 'Normal',      color: '#10B981', comment: '...' };
        if (bmi < 30)   return { label: 'Overweight',  color: '#F59E0B', comment: '...' };
        if (bmi < 35)   return { label: 'Obese (Class I)', color: '#F97316', comment: '...' };
        return           { label: 'Obese (Class II+)', color: '#EF4444', comment: '...' };
      }
      expect(bmiCategory(17)?.label).toBe('Underweight');
      expect(bmiCategory(22)?.label).toBe('Normal');
      expect(bmiCategory(27)?.label).toBe('Overweight');
      expect(bmiCategory(32)?.label).toBe('Obese (Class I)');
      expect(bmiCategory(40)?.label).toBe('Obese (Class II+)');
      expect(bmiCategory(null)).toBeNull();
      logResult('BMI categories: all 5 ranges correct', true);
    } catch (e) { logResult('BMI categories: all 5 ranges correct', false, e); throw e; }
  });
});

