// 6. LOGIC â€” Zenova Score calculation (isolated)
// â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•

describe('Zenova Score â€” isolated calculation logic', () => {

  function calcScore(
    calPct: number,     // 0-1
    selectedType: string | null,
    moodRating: number, // 1-5, 0 = not rated
    sleepPct: number,   // 0-1
  ) {
    const foodScore  = Math.min(Math.round(calPct * 25), 25);
    const moveScore  = selectedType === 'rest' ? 10 : selectedType ? 25 : 0;
    const moodScore  = moodRating > 0 ? Math.round(moodRating * 5) : 0;
    const sleepScore = sleepPct > 0 ? Math.min(Math.round(sleepPct * 25), 25) : 0;
    return Math.min(foodScore + moveScore + moodScore + sleepScore, 100);
  }

  test('perfect day = 100 score', () => {
    try {
      const score = calcScore(1.0, 'chest', 5, 1.0);
      // food=25, move=25, mood=25, sleep=25 â†’ 100
      expect(score).toBe(100);
      logResult('Zenova Score: perfect day = 100', true);
    } catch (e) { logResult('Zenova Score: perfect day = 100', false, e); throw e; }
  });

  test('zero day = 0 score', () => {
    try {
      const score = calcScore(0, null, 0, 0);
      expect(score).toBe(0);
      logResult('Zenova Score: empty day = 0', true);
    } catch (e) { logResult('Zenova Score: empty day = 0', false, e); throw e; }
  });

  test('rest day gives 10 move points (not 0 or 25)', () => {
    try {
      const score = calcScore(0, 'rest', 0, 0);
      expect(score).toBe(10);
      logResult('Zenova Score: rest day = 10 move points', true);
    } catch (e) { logResult('Zenova Score: rest day = 10 move points', false, e); throw e; }
  });

  test('score is capped at 100', () => {
    try {
      // Even with all maxed, should not exceed 100
      const score = calcScore(2.0, 'chest', 5, 2.0);
      expect(score).toBeLessThanOrEqual(100);
      logResult('Zenova Score: capped at 100', true);
    } catch (e) { logResult('Zenova Score: capped at 100', false, e); throw e; }
  });

  test('calorie overcount doesnt boost food score beyond 25', () => {
    try {
      const foodScore = Math.min(Math.round(2.0 * 25), 25);
      expect(foodScore).toBe(25);
      logResult('Zenova Score: foodScore capped at 25', true);
    } catch (e) { logResult('Zenova Score: foodScore capped at 25', false, e); throw e; }
  });
});

