// 13. UNIT â€” secureStorage chunking logic
// â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•

describe('services/secureStorage.ts â€” chunking logic', () => {

  const CHUNK_SIZE = 1800;

  test('string within limit needs only 1 chunk', () => {
    try {
      const small = 'x'.repeat(1799);
      const chunks: string[] = [];
      for (let i = 0; i < small.length; i += CHUNK_SIZE) chunks.push(small.slice(i, i + CHUNK_SIZE));
      expect(chunks).toHaveLength(1);
      logResult('secureStorage: small string â†’ 1 chunk', true);
    } catch (e) { logResult('secureStorage: small string â†’ 1 chunk', false, e); throw e; }
  });

  test('large string split into correct number of chunks', () => {
    try {
      const large = 'x'.repeat(5400); // 3 chunks of 1800
      const chunks: string[] = [];
      for (let i = 0; i < large.length; i += CHUNK_SIZE) chunks.push(large.slice(i, i + CHUNK_SIZE));
      expect(chunks).toHaveLength(3);
      logResult('secureStorage: 5400 chars â†’ 3 chunks', true);
    } catch (e) { logResult('secureStorage: 5400 chars â†’ 3 chunks', false, e); throw e; }
  });

  test('reassembled chunks equal original string', () => {
    try {
      const original = 'A'.repeat(4500);
      const chunks: string[] = [];
      for (let i = 0; i < original.length; i += CHUNK_SIZE) chunks.push(original.slice(i, i + CHUNK_SIZE));
      const reassembled = chunks.join('');
      expect(reassembled).toBe(original);
      logResult('secureStorage: chunks reassemble to original', true);
    } catch (e) { logResult('secureStorage: chunks reassemble to original', false, e); throw e; }
  });

  test('key sanitizer removes invalid chars', () => {
    try {
      function sanitizeKey(key: string): string {
        return key.replace(/[^a-zA-Z0-9._-]/g, '_');
      }
      expect(sanitizeKey('zenova-user-storage')).toBe('zenova-user-storage');
      expect(sanitizeKey('key with spaces!')).toBe('key_with_spaces_');
      expect(sanitizeKey('zenova:user:key')).toBe('zenova_user_key');
      logResult('secureStorage: sanitizeKey replaces invalid chars', true);
    } catch (e) { logResult('secureStorage: sanitizeKey', false, e); throw e; }
  });
});

// â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
// 14. INTEGRATION â€” Store state management
// â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•

describe('store logic â€” state management', () => {

  test('groupByDate merges same-day workouts correctly', () => {
    try {
      type CW = { id: string; name: string; date: string; calories: number; exercisesDone: number; exercisesTotal: number; icon: string; bodyPart: string; duration: string; exerciseWeights?: Record<string, number>; timestamp: number };

      function groupByDate(history: CW[]): CW[] {
        const map = new Map<string, CW>();
        for (const w of history) {
          const existing = map.get(w.date);
          if (!existing) {
            map.set(w.date, { ...w, exerciseWeights: { ...w.exerciseWeights } });
          } else {
            existing.calories += w.calories;
            existing.exercisesDone  += w.exercisesDone;
            existing.exercisesTotal += w.exercisesTotal;
          }
        }
        return Array.from(map.values());
      }

      const history: CW[] = [
        { id: '1', name: 'Chest', date: '2025-01-01', calories: 300, exercisesDone: 5, exercisesTotal: 6, icon: 'ğŸ’ª', bodyPart: 'chest', duration: '45', timestamp: 1 },
        { id: '2', name: 'Cardio', date: '2025-01-01', calories: 200, exercisesDone: 3, exercisesTotal: 4, icon: 'ğŸƒ', bodyPart: 'cardio', duration: '30', timestamp: 2 },
        { id: '3', name: 'Back', date: '2025-01-02', calories: 350, exercisesDone: 6, exercisesTotal: 6, icon: 'ğŸ’ª', bodyPart: 'back', duration: '50', timestamp: 3 },
      ];
      const grouped = groupByDate(history);
      expect(grouped).toHaveLength(2); // 2 unique dates
      const jan1 = grouped.find(g => g.date === '2025-01-01');
      expect(jan1?.calories).toBe(500); // 300 + 200
      logResult('groupByDate: merges same-day calories correctly', true);
    } catch (e) { logResult('groupByDate: merges same-day calories', false, e); throw e; }
  });

  test('recoveryStore saveEntry replaces todays entry', () => {
    try {
      type RecoveryEntry = { mood: number; energy: number; stress: number; sleepHours?: number; date: string };
      const today = todayStr();

      // Simulate the store's saveEntry logic
      let entries: RecoveryEntry[] = [{ mood: 3, energy: 3, stress: 3, date: today }];
      const newEntry = { mood: 5, energy: 4, stress: 2, sleepHours: 8 };
      entries = [...entries.filter((e) => e.date !== today), { ...newEntry, date: today }];

      expect(entries).toHaveLength(1); // still 1 entry for today
      expect(entries[0].mood).toBe(5); // updated
      logResult('recoveryStore: saveEntry replaces existing date', true);
    } catch (e) { logResult('recoveryStore: saveEntry replaces existing date', false, e); throw e; }
  });

  test('workoutStore history capped at 50 entries', () => {
    try {
      // Simulate addWorkout logic
      let history: { id: string }[] = Array.from({ length: 50 }, (_, i) => ({ id: `old-${i}` }));
      const newWorkout = { id: 'new' };
      history = [newWorkout, ...history].slice(0, 50);
      expect(history).toHaveLength(50);
      expect(history[0].id).toBe('new');
      expect(history[49].id).toBe('old-48'); // last old entry
      logResult('workoutStore: history capped at 50', true);
    } catch (e) { logResult('workoutStore: history capped at 50', false, e); throw e; }
  });

  test('workoutStore updateWorkout replaces entry in place (F10 no double-count)', () => {
    try {
      type W = { id: string; date: string; name: string; calories: number; timestamp: number };
      const today = todayStr();
      let history: W[] = [
        { id: 'a1', date: today, name: 'Full Body â€” Day 1', calories: 300, timestamp: 1 },
        { id: 'b2', date: '2026-01-01', name: 'Full Body â€” Day 1', calories: 250, timestamp: 0 },
      ];

      // Simulate handleFinish dedupe: same day + same plan name â†’ existing found
      const entry = { name: 'Full Body â€” Day 1', calories: 420 };
      const existing = history.find((w) => w.date === today && w.name === entry.name);
      expect(existing?.id).toBe('a1');

      // Simulate updateWorkout: replace fields, keep id + date, fresh timestamp
      history = history.map((w) =>
        w.id === existing!.id ? { ...w, ...entry, id: w.id, date: w.date, timestamp: 999 } : w
      );

      expect(history).toHaveLength(2); // no new entry added
      const todayEntries = history.filter((w) => w.date === today);
      expect(todayEntries).toHaveLength(1);
      expect(todayEntries[0].calories).toBe(420); // replaced, not 300+420
      expect(todayEntries[0].id).toBe('a1');
      logResult('workoutStore: updateWorkout replaces in place (F10)', true);
    } catch (e) { logResult('workoutStore: updateWorkout replaces in place (F10)', false, e); throw e; }
  });

  test('activeMins prefers numeric durationMinutes over parsing duration string (F4)', () => {
    try {
      type W = { date: string; duration: string; durationMinutes?: number };
      const today = todayStr();
      const history: W[] = [
        { date: today, duration: '~45 min', durationMinutes: 45 }, // new record: parse would give 0
        { date: today, duration: '30 min' },                       // legacy record: string parse
        { date: '2026-01-01', duration: '60 min', durationMinutes: 60 }, // other day: excluded
      ];
      const activeMins = history
        .filter((w) => w.date === today)
        .reduce((sum, w) => sum + (w.durationMinutes ?? (parseInt(w.duration) || 0)), 0);
      expect(activeMins).toBe(75);
      logResult('activeMins: durationMinutes preferred over string parse (F4)', true);
    } catch (e) { logResult('activeMins: durationMinutes preferred (F4)', false, e); throw e; }
  });

  test('aiChatStore daily limit survives clearHistory (F12)', () => {
    try {
      type DailyCount = { date: string; count: number };
      type Msg = { role: string; createdAt?: string };
      const today = todayStr();
      const userId = 'u1';

      // Simulate getTodayUsage: max(date-keyed counter, message-derived count)
      const usage = (
        chats: Record<string, Msg[]>,
        dailyCounts: Record<string, DailyCount>,
      ) => {
        const dc = dailyCounts[userId];
        const counted = dc?.date === today ? dc.count : 0;
        const fromMsgs = (chats[userId] ?? []).filter(
          (m) => m.role === 'user' && !!m.createdAt && m.createdAt.startsWith(today)
        ).length;
        return Math.max(counted, fromMsgs);
      };

      // 10 user messages sent â†’ counter at 10
      let chats: Record<string, Msg[]> = {
        [userId]: Array.from({ length: 10 }, () => ({ role: 'user', createdAt: `${today}T10:00:00.000Z` })),
      };
      let dailyCounts: Record<string, DailyCount> = { [userId]: { date: today, count: 10 } };
      expect(usage(chats, dailyCounts)).toBe(10);

      // "Clear conversation" wipes messages but NOT the counter â†’ still gated
      chats = { [userId]: [] };
      expect(usage(chats, dailyCounts)).toBe(10);

      // Next calendar day â†’ counter stale, usage resets to 0
      dailyCounts = { [userId]: { date: '2020-01-01', count: 10 } };
      expect(usage(chats, dailyCounts)).toBe(0);

      // Legacy path: counter absent but old messages persisted â†’ message count wins
      chats = { [userId]: [{ role: 'user', createdAt: `${today}T09:00:00.000Z` }] };
      dailyCounts = {};
      expect(usage(chats, dailyCounts)).toBe(1);

      logResult('aiChatStore: daily limit survives clearHistory (F12)', true);
    } catch (e) { logResult('aiChatStore: daily limit survives clearHistory (F12)', false, e); throw e; }
  });

  test('aiChatStore caps messages at 50 per user', () => {
    try {
      type ChatMessage = { id: string; role: string; text: string };
      let messages: ChatMessage[] = Array.from({ length: 50 }, (_, i) => ({ id: `${i}`, role: 'user', text: 'msg' }));
      const newMsg: ChatMessage = { id: 'new', role: 'assistant', text: 'reply' };
      const updated = [...messages.slice(-49), newMsg];
      expect(updated).toHaveLength(50);
      logResult('aiChatStore: messages capped at 50 per user', true);
    } catch (e) { logResult('aiChatStore: messages capped at 50', false, e); throw e; }
  });
});

